mapper.select:
SELECT CUST.RELAT_YN ,GETCODENAME(CUST.GATE_CD, 'NH0005', CUST.RELAT_YN, #{ses.langCd}) AS RELAT_YN_NM , CUST.CORP_TYPE ,GETCODENAME(CUST.GATE_CD, 'NH0002', CUST.CORP_TYPE, #{ses.langCd}) AS CORP_TYPE_NM , CUST.CUST_CD ,GETCUSTNAME(CUST.GATE_CD, CUST.CUST_CD) AS CUST_NM , CUST.IRS_NUM , OGDP.DEPT_CD , OGDP.DEPT_NM , OGDP.BRANCH_FLAG , CUST.CUST_CD '-' OGDP.DEPT_CD AS CHECK_DUP FROM STOCCUST CUST JOIN STOCOGDP OGDP ON (CUST.GATE_CD = OGDP.GATE_CD AND CUST.CUST_CD = OGDP.BUYER_CD) WHERE OGDP.GATE_CD = #{ses.gateCd}
AND CUST.RELAT_YN = #{RELAT_YN}
AND CUST.CORP_TYPE = #{CORP_TYPE}
AND CUST.CUST_CD = #{CUST_CD}
AND OGDP.DEPT_CD = #{DEPT_CD}
AND (UPPER(GETDEPTNAME(CUST.GATE_CD, CUST.CUST_CD, OGDP.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%' OR UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
AND UPPER(GETDEPTNAME(CUST.GATE_CD, CUST.CUST_CD, OGDP.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%'
AND CUST.IRS_NUM LIKE '%' UPPER(#{IRS_NUM}) '%'
AND OGDP.BRANCH_FLAG = #{BRANCH_FLAG}
AND OGDP.DEL_FLAG = '0'

SELECT CUST_CD "value", CUST_NM "text"
FROM STOCCUST
WHERE GATE_CD = #{ses.gateCd}
AND RELAT_YN  = #{RELAT_YN}
AND CORP_TYPE = #{CORP_TYPE}
AND DEL_FLAG  = '0'

choose.when:
SELECT DISTINCT CUST.RELAT_YN ,GETCODENAME(CUST.GATE_CD, 'NH0005', CUST.RELAT_YN, #{ses.langCd}) AS RELAT_YN_NM , CUST.CORP_TYPE ,GETCODENAME(CUST.GATE_CD, 'NH0002', CUST.CORP_TYPE, #{ses.langCd}) AS CORP_TYPE_NM , CUST.CUST_CD ,GETCUSTNAME(CUST.GATE_CD, CUST.CUST_CD) AS CUST_NM , CUST.IRS_NUM , CVUR.DEPT_CD , CVUR.DEPT_NM , CVUR.USER_ID ,GETUSERNAME(CVUR.GATE_CD, CVUR.USER_ID, #{ses.langCd}) AS USER_NM , CVUR.POSITION_NM , CVUR.DUTY_NM , OGDP.BRANCH_FLAG ,CVUR.EMAIL AS EMAIL ,CVUR.CELL_NUM AS CELL_NUM ,CUST.CEO_USER_NM AS CEO_USER_NM FROM STOCBACP BACP JOIN STOCCVUR CVUR ON (CVUR.GATE_CD = BACP.GATE_CD AND CVUR.COMPANY_CD = BACP.BUYER_CD AND CVUR.USER_ID = BACP.CTRL_USER_ID AND CVUR.USER_TYPE = 'B' AND CVUR.DEL_FLAG = '0') LEFT JOIN STOCCUST CUST ON (CUST.GATE_CD = BACP.GATE_CD AND CUST.CUST_CD = BACP.BUYER_CD AND CUST.DEL_FLAG = '0') LEFT JOIN STOCOGDP OGDP ON (CVUR.GATE_CD = OGDP.GATE_CD AND CVUR.COMPANY_CD = OGDP.BUYER_CD AND CVUR.DEPT_CD = OGDP.DEPT_CD AND OGDP.DEL_FLAG = '0') WHERE BACP.GATE_CD = #{ses.gateCd}
AND BACP.CTRL_CD IN
#{item}
AND CVUR.COMPANY_CD = #{CUST_CD}
AND CVUR.DEPT_CD = #{DEPT_CD}
AND (UPPER(GETDEPTNAME(CVUR.GATE_CD, CVUR.COMPANY_CD, CVUR.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%' OR UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
AND UPPER(GETDEPTNAME(CVUR.GATE_CD, CVUR.COMPANY_CD, CVUR.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%'
AND UPPER(CVUR.USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
AND UPPER(GETUSERNAME(CVUR.GATE_CD, CVUR.USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{USER_NM}) '%'
AND CUST.IRS_NUM LIKE '%' UPPER(#{IRS_NUM}) '%'
AND CUST.RELAT_YN = #{RELAT_YN}
AND CUST.CORP_TYPE = #{CORP_TYPE}
AND OGDP.BRANCH_FLAG = #{BRANCH_FLAG}
AND BACP.DEL_FLAG = '0' AND BACP.USE_FLAG = '1'

choose.otherwise:
SELECT CUST.RELAT_YN ,GETCODENAME(CUST.GATE_CD, 'NH0005', CUST.RELAT_YN, #{ses.langCd}) AS RELAT_YN_NM , CUST.CORP_TYPE ,GETCODENAME(CUST.GATE_CD, 'NH0002', CUST.CORP_TYPE, #{ses.langCd}) AS CORP_TYPE_NM , CUST.CUST_CD ,GETCUSTNAME(CUST.GATE_CD, CUST.CUST_CD) AS CUST_NM , CUST.IRS_NUM , CVUR.DEPT_CD , CVUR.DEPT_NM , CVUR.USER_ID ,GETUSERNAME(CVUR.GATE_CD, CVUR.USER_ID, #{ses.langCd}) AS USER_NM , CVUR.POSITION_NM , CVUR.DUTY_NM , OGDP.BRANCH_FLAG ,CVUR.EMAIL AS EMAIL ,CVUR.CELL_NUM AS CELL_NUM ,CUST.CEO_USER_NM AS CEO_USER_NM FROM STOCCVUR CVUR JOIN STOCCUST CUST ON (CVUR.GATE_CD = CUST.GATE_CD AND CVUR.COMPANY_CD = CUST.CUST_CD
AND CUST.RELAT_YN = #{RELAT_YN}
AND CUST.CORP_TYPE = #{CORP_TYPE}
AND CUST.DEL_FLAG = '0') JOIN STOCOGDP OGDP ON (CVUR.GATE_CD = OGDP.GATE_CD AND CVUR.COMPANY_CD = OGDP.BUYER_CD AND CVUR.DEPT_CD = OGDP.DEPT_CD
AND OGDP.BRANCH_FLAG = #{BRANCH_FLAG}
AND OGDP.DEL_FLAG = '0') WHERE CVUR.GATE_CD = #{ses.gateCd}
AND CVUR.COMPANY_CD = #{CUST_CD}
AND CVUR.DEPT_CD = #{DEPT_CD}
AND (UPPER(GETDEPTNAME(CVUR.GATE_CD, CVUR.COMPANY_CD, CVUR.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%' OR UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
AND UPPER(GETDEPTNAME(CVUR.GATE_CD, CVUR.COMPANY_CD, CVUR.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%'
AND UPPER(CVUR.USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
AND UPPER(GETUSERNAME(CVUR.GATE_CD, CVUR.USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{USER_NM}) '%'
AND CVUR.DEL_FLAG = '0' AND CVUR.USER_TYPE = 'B' AND CVUR.USE_FLAG = '1'

mapper.select:
SELECT CUST.RELAT_YN ,GETCODENAME(CUST.GATE_CD, 'NH0005', CUST.RELAT_YN, #{ses.langCd}) AS RELAT_YN_NM , CUST.CORP_TYPE ,GETCODENAME(CUST.GATE_CD, 'NH0002', CUST.CORP_TYPE, #{ses.langCd}) AS CORP_TYPE_NM , CUST.CUST_CD , CUST.CUST_CD AS VENDOR_CD ,GETCUSTNAME(CUST.GATE_CD, CUST.CUST_CD) AS CUST_NM ,GETBUYERDEPTNAME(OGDP.GATE_CD, OGDP.BUYER_CD, OGDP.DEPT_CD, #{ses.langCd}) AS VENDOR_NM ,CVUR.USER_NM AS VENDOR_PIC_USER_NM ,CVUR.EMAIL AS VENDOR_PIC_USER_EMAIL ,CVUR.CELL_NUM AS VENDOR_PIC_USER_CELL_NUM , CUST.IRS_NUM , OGDP.DEPT_CD , OGDP.DEPT_CD AS VENDOR_DEPT_CD , OGDP.DEPT_NM , OGDP.BRANCH_FLAG , CUST.CUST_CD '-' OGDP.DEPT_CD AS CHECK_DUP , OGDP.ZONE_CD ,GETCODENAME(CUST.GATE_CD, 'NH0049', OGDP.ZONE_CD, #{ses.langCd}) AS ZONE_CD_NM FROM STOCCUST CUST JOIN STOCOGDP OGDP ON (CUST.GATE_CD = OGDP.GATE_CD AND CUST.CUST_CD = OGDP.BUYER_CD AND OGDP.DEL_FLAG = '0') LEFT JOIN STOCCVUR CVUR ON (CUST.GATE_CD = CVUR.GATE_CD AND CUST.CUST_CD = CVUR.COMPANY_CD AND CVUR.USER_ID = (SELECT MAX(USER_ID) FROM STOCCVUR WHERE GATE_CD = CVUR.GATE_CD AND COMPANY_CD = CUST.CUST_CD AND MNG_YN = '1' -- 관리자 AND USE_FLAG = '1' -- 사용여부 AND WORK_TYPE = '1' -- 주무서무 AND BLOCK_FLAG = '0' -- BLOCK여부 AND DEL_FLAG = '0') AND CVUR.DEL_FLAG = '0') WHERE CUST.GATE_CD = #{ses.gateCd}
AND CUST.RELAT_YN = #{RELAT_YN}
AND CUST.CORP_TYPE = #{CORP_TYPE}
AND CUST.CUST_CD = #{CUST_CD}
AND (UPPER(GETDEPTNAME(CUST.GATE_CD, CUST.CUST_CD, OGDP.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%' OR UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
AND UPPER(GETDEPTNAME(CUST.GATE_CD, CUST.CUST_CD, OGDP.DEPT_CD, #{ses.langCd})) LIKE '%' UPPER(#{DEPT_NM}) '%'
AND CUST.IRS_NUM LIKE '%' UPPER(#{IRS_NUM}) '%'
AND OGDP.DEPT_CD = #{DEPT_CD}
AND OGDP.BRANCH_FLAG = #{BRANCH_FLAG}
AND OGDP.ZONE_CD = #{ZONE_CD}
